return-response.set-body:
@{
                var corsOrigin = context.Variables.GetValueOrDefault("corsOrigin", "");
                var apiId = context.Api.Id;
                return new JObject(
                    new JProperty("api", apiId),
                    new JProperty("message", "Hello from " + apiId),
                    new JProperty("corsAllowed", !string.IsNullOrEmpty(corsOrigin)),
                    new JProperty("allowedOrigin", corsOrigin)
                ).ToString();
            }
